const t = ($json.text||'').toLowerCase();
let intent='otro';
if(t.includes('cita')) intent='cita';
else if(t.includes('factura')||t.includes('pago')) intent='facturacion';
else if(t.includes('estado')||t.includes('caso')) intent='estado_caso';
else if(t.includes('urgente')||t.includes('hoy')||t.includes('mañana')) intent='urgencia';
else if(t.length>0) intent='consulta_nueva';
return [{json:{...$json,intent}}];
